INSERT INTO `badges` VALUES
(2,'Bienvenido a la seguridad','Se consigue luego de haber perdido un módulo/curso. Primer paso en tu camino de aprendizaje.','Award','bienvenida-seguridad.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(3,'Se enciende la Racha','Participando en actividades por dos días seguidos. ¡Mantén el ritmo!','Zap','racha-encendida.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(4,'Club de la Velocidad I','Terminar un módulo en 5 min o menos. ¡Eres un rayo!','Zap','club-velocidad.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-18 01:49:36',10),
(5,'Lo mejor de la Sabana','Completa dos módulos seguidos. Un verdadero experto en la materia.','Star','mejor-sabana.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(6,'El inicio de la seguridad','Iniciar un Módulo. El conocimiento es tu mejor defensa.','Bell','inicio-seguridad.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(7,'Un gran poder lleva una gran seguridad','Terminar el módulo 1. Has fortalecido tus defensas básicas.','ShieldCheck','gran-poder-seguridad.svg','module_completion','1','2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(8,'Más seguridad','Obteniendo todas las insignias iniciales. El nivel máximo de protección.','Crown','mas-seguridad.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(9,'Desafío aceptado','Entra en la clasificación de puntos. Has demostrado tu compromiso.','Target','desafio-aceptado.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(10,'Seguridad sin igual','Descarga 1 recurso adicional de cualquier curso. Buscando la excelencia.','Search','seguridad-sin-igual.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(11,'Seguridad contra lo peor','Termina el módulo 4. Eres un experto en detección de amenazas.','ShieldAlert','seguridad-contra-peor.svg','module_completion','4','2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(12,'Seguridad Legendaria','Termina en el top 10 de la clasificación. Un referente para la institución.','Trophy','seguridad-legendaria.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(13,'Ciber-Prestigio','Acumula una gran cantidad de puntos en la clasificación. Reconocimiento a tu trayectoria.','Award','ciber-prestigio.svg','total_points','1000','2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(14,'Era de la Ciber Seguridad','Termina todos los módulos del programa. Graduado en CGR Segur@.','Trophy','era-ciberseguridad.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(15,'Enfrentamiento por la seguridad','Defiende tu posición en la tabla de posiciones por varios días.','Shield','enfrentamiento-seguridad.svg','manual',NULL,'2026-02-16 20:10:03','2026-02-16 20:10:03',10),
(16,'Club de la Velocidad II','Terminar un módulo en 10 min o menos. Demuestra tu agilidad mental.','Zap','club-velocidad.svg','manual',NULL,'2026-02-18 01:49:36','2026-02-18 01:51:34',10),
(17,'Club de la Velocidad III','Terminar un módulo en 20 min o menos. ¡Mantienes un excelente ritmo!','Zap','club-velocidad.svg','manual',NULL,'2026-02-18 03:04:35','2026-02-18 03:04:35',10),
(18,'Anomalía del Sistema III','Has encontrado un fallo crítico en la Matrix que no debería existir. Al reportarlo al CISO, has demostrado que tu percepción va más allá de lo que la Matrix intenta mostrarte.','Award','bienvenida-seguridad.svg','manual',NULL,'2026-04-23 21:06:23','2026-04-30 21:16:11',50),
(19,'Enlace con el Operador','Has sabido cuándo levantar el auricular. Esta insignia reconoce tu inteligencia para pedir soporte al CISO para usar la plataforma CGR Segura y optimizar tu rendimiento en la simulación.','Award','seguridad-sin-igual.svg','manual',NULL,'2026-04-23 21:11:03','2026-04-27 16:27:56',10),
(20,'Anomalía del Sistema I','Has encontrado un fallo en la Matrix que no debería existir. Al reportarlo al CISO, has demostrado que tu percepción va más allá de lo que la Matrix intenta mostrarte y has mejorado la plataforma.','Award','bienvenida-seguridad.svg','manual',NULL,'2026-04-24 02:42:24','2026-04-27 16:44:15',10),
(21,'Arcade Replay','El conocimiento es un músculo que se entrena. Ganada por rejugar los niveles finales de CGR Segura hasta dominar cada mecánica y lograr una ejecución libre de riesgos.','Award','mas-seguridad.svg','manual',NULL,'2026-04-29 19:15:00','2026-04-29 19:15:00',5),
(22,'Anomalía del Sistema II','Has encontrado un fallo medio en la Matrix que no debería existir. Al reportarlo al CISO, has demostrado que tu percepción va más allá de lo que la Matrix intenta mostrarte y has mejorado la plataforma.','Award','bienvenida-seguridad.svg','manual',NULL,'2026-04-30 21:15:40','2026-04-30 21:15:59',15);
