INSERT INTO `lesson_contents` VALUES
(14,9,'asdasd','text','{\"text\":\"sadsadsadasdasdsa\"}',1,1,1,'2026-02-12 16:44:07','2026-02-12 16:44:07'),
(34,17,'Identidad Digital','heading','{\"text\":\"Identidad Digital\"}',1,0,0,'2026-02-18 04:44:03','2026-04-13 00:35:26'),
(35,17,'Roles de Seguridad','text','{\"text\":\"La contraseña es la llave maestra que permite el acceso a los recursos, sistemas y datos necesarios para el cumplimiento de nuestras funciones.\\n\\nComo parte de las recomendaciones que debemos tomar en cuenta con respecto  a las contraseñas:\"}',3,0,0,'2026-02-18 04:44:03','2026-04-13 16:36:09'),
(37,18,'Contrasenas Robustas','heading','{\"text\":\"¿Cómo puedo gestionar entonces mis contraseñas?\"}',1,0,0,'2026-02-18 04:44:03','2026-04-13 03:33:29'),
(38,18,'Gestion de Passwords','text','{\"text\":\"En la lección anterior vimos los riesgos de tener contraseñas inseguras y que se filtren nuestras cuentas. Ahora vamos a ver como protegernos ante este panorama.\"}',2,0,0,'2026-02-18 04:44:03','2026-04-13 03:35:18'),
(39,18,'Gestor de Contraseñas','text','{\"text\":\"Un gestor de contraseñas es una herramienta diseñada para almacenar, organizar y proteger todas las credenciales de acceso (usuarios y claves) en una \\\"bóveda\\\" digital cifrada. En lugar de memorizar decenas de claves complejas, solo necesitamos recordar una única contraseña maestra para desbloquear el resto.\\n\\nAdemás tenemos una serie de ventajas:\"}',5,0,0,'2026-02-18 04:44:03','2026-05-04 19:23:23'),
(40,19,'Tu nueva plataforma','heading','{\"text\":\"Tu nueva plataforma de aprendizaje\"}',1,0,1,'2026-02-18 04:56:50','2026-04-12 22:43:29'),
(41,19,'Introduccion','text','{\"text\":\"Este plan de capacitación está diseñado para los funcionarios de la Contraloría General de la República (CGR), con el objetivo de fomentar una cultura de ciberseguridad. Se basa en los nuevos Lineamientos de Seguridad de la Información ISO/IEC 27001:2022 de la CGR, y busca ser dinámico, interactivo y adaptable a las necesidades de todos los funcionarios.\\n\\nA diferencia de otros cursos virtuales, este curso tiene un enfoque de \\\"Gamificación\\\". Viviras una experiencia interactiva, con videos, laboratorios y desafios que te haran subir de nivel como si estuvieras en un juego de video.\"}',2,0,0,'2026-02-18 04:56:50','2026-03-11 21:09:36'),
(44,20,'El Centro de Control','heading','{\"text\":\"Centro de Control\"}',1,0,2,'2026-02-18 04:56:50','2026-04-12 22:44:57'),
(45,20,'El Dashboard','text','{\"text\":\"Al iniciar sesión, el Dashboard mostrará de inmediato la última lección recibida. Podrá ver la barra de progreso de los módulos activos, el balance de puntos y las últimas insignias obtenidas.\"}',2,0,0,'2026-02-18 04:56:50','2026-04-09 16:05:49'),
(46,20,'Los Modulos','text','{\"text\":\"En el apartado de Módulos podrá visualizar la ruta de aprendizaje completa. Para garantizar un proceso secuencial, algunos cursos se encuentran bloqueados temporalmente y se habilitarán de forma automática una vez que usted complete los requisitos previos de cada etapa\"}',3,0,0,'2026-02-18 04:56:50','2026-05-04 19:21:05'),
(47,21,'Compite con Honor','heading','{\"text\":\"¿Qué es la Gamificación?\"}',1,0,2,'2026-02-18 04:56:50','2026-04-12 22:43:39'),
(48,21,'Los Puntos','text','{\"text\":\"Proviene de \\\"Game\\\" juego en inglés y es una metodología que transforma el aprendizaje en una experiencia interactiva mediante el uso de dinámicas de juego. El objetivo es reconocer su progreso y premiar su dedicación a medida que avanza en el cronograma del programa de capacitación.\\n\\nEn este programa, cada acción cuenta. Visualizar los contenidos, completar las lecciones y, sobre todo, obtener resultados destacados en los quices, otorgará Puntos de Experiencia (PTS). \"}',2,0,0,'2026-02-18 04:56:50','2026-04-15 21:30:30'),
(57,19,'Metodología','heading','{\"text\":\"Metodología\"}',3,0,0,'2026-03-11 21:13:29','2026-03-11 21:13:32'),
(58,19,'Metodologia','bullets','{\"items\":[{\"title\":\"Módulos de E-learning\",\"text\":\"Contenidos claros, concisos, con videos cortos, infografías y cuestionarios interactivos. Cada módulo tendrá una duración aproximada de 30-45 minutos\"},{\"title\":\"Talleres Interactivos (presenciales/virtuales)\",\"text\":\"Sesiones prácticas y participativas en grupos pequeños, enfocadas en escenarios reales y resolución de problemas\"},{\"title\":\"Simulacros y Pruebas de Ingeniería Social\",\"text\":\"Ejercicios prácticos controlados para evaluar el nivel de madurez y reforzar el aprendizaje de forma vivencial\"},{\"title\":\"Gamificación\",\"text\":\"Implementación de insignias, tablas de clasificación o pequeños desafíos para motivar la participación y el aprendizaje continuo.\"}]}',6,0,0,'2026-03-11 21:22:52','2026-03-11 21:22:52'),
(59,19,'Temáticas y Contenidos Clave','heading','{\"text\":\"Temáticas y Contenidos Clave\"}',7,0,0,'2026-03-11 21:24:29','2026-03-11 21:24:29'),
(61,19,'Cronograma','image','{\"file_url\":\"/uploads/course_content/076cd021-90c5-4283-9c71-95803245f023.svg\",\"original_name\":\"CronogramaV2.svg\",\"mime_type\":\"image/svg+xml\",\"size\":29576}',9,0,0,'2026-03-13 18:05:29','2026-04-08 04:36:10'),
(62,20,'Menu','image','{\"file_url\":\"/uploads/course_content/1773433438594-386559912.gif\",\"original_name\":\"Animation.gif\",\"mime_type\":\"image/gif\",\"size\":3584190}',4,0,0,'2026-03-13 20:23:58','2026-03-13 20:23:58'),
(63,19,'Nota','note','{\"text\":\"La realización de este curso es de carácter obligatorio. Aunque los módulos se habilitarán mensualmente y no cuentan con una fecha límite estricta de entrega, es recomendado completarlos conforme se publiquen para mantener el aprendizaje al día. Eso sí, es requisito indispensable haber finalizado la totalidad del programa antes de concluir el año.\"}',10,0,0,'2026-04-08 04:36:49','2026-04-29 13:58:46'),
(65,26,'Qué son las insignias?','text','{\"text\":\"Dentro de la plataforma puede ganar insignias. Estas insignias no son solo adornos. Representan logros especificos como velocidad, rachas o maestria. \\n\\nCada vez que gane una insignia, verá una celebración en pantalla y se guardará en su perfil.\"}',2,0,0,'2026-04-08 18:39:21','2026-04-09 07:40:55'),
(66,26,'Qué son las insignias?','heading','{\"text\":\"Qué son las insignias?\"}',1,0,1,'2026-04-08 18:39:47','2026-04-12 22:44:04'),
(67,26,'Insignias','image','{\"file_url\":\"/uploads/course_content/426e50ef-e72d-47e1-b66a-f3a9e6feca9a.png\",\"original_name\":\"Screenshot_42.png\",\"mime_type\":\"image/png\",\"size\":112959}',3,0,0,'2026-04-08 18:40:10','2026-04-08 18:40:10'),
(69,23,'¿Cómo funciona el Ranking en CGR Segura?','heading','{\"text\":\"¿Cómo funciona el Ranking en CGR Segura?\"}',1,0,0,'2026-04-08 19:10:42','2026-04-08 20:00:44'),
(70,23,'Visita frecuentemente el Ranking para ver quien lidera la institucion en conocimientos de seguridad. ¿Tienes lo necesario para estar en el primer lugar?','text','{\"text\":\"Al interactuar con la plataforma y completar lecciones, se van acumulando puntos. Puede ver el ranking en el menu superior\"}',2,0,0,'2026-04-08 19:11:21','2026-04-08 20:02:54'),
(71,23,'r1','image','{\"file_url\":\"/uploads/course_content/cdd39876-f8c2-43d9-bc77-5be77b5d47c8.png\",\"original_name\":\"Screenshot_46.png\",\"mime_type\":\"image/png\",\"size\":536882}',6,0,0,'2026-04-08 19:59:34','2026-04-08 20:08:50'),
(72,23,'Existen tres rankings que van a visualizar:','text','{\"text\":\"Existen tres rankings que van a visualizar:\"}',4,0,0,'2026-04-08 19:59:42','2026-04-08 20:05:40'),
(73,23,'eqw','image','{\"file_url\":\"/uploads/course_content/0387c618-9a5e-417f-92e3-d7bfcda0c275.png\",\"original_name\":\"Screenshot_47.png\",\"mime_type\":\"image/png\",\"size\":580382}',7,0,0,'2026-04-08 19:59:49','2026-04-08 20:08:57'),
(74,23,'Donde esta','image','{\"file_url\":\"/uploads/course_content/91f1ec0f-2bb3-4af9-9d82-7640d4db18ca.png\",\"original_name\":\"Screenshot_48.png\",\"mime_type\":\"image/png\",\"size\":489617}',3,0,0,'2026-04-08 20:02:16','2026-04-08 20:04:47'),
(75,23,'asdasdsa','bullets','{\"items\":[{\"title\":\"1. Mi área\",\"text\":\"Muestra su posición dentro de su área\"},{\"title\":\"2. Por áreas \",\"text\":\"Muestra el listado de todas las áreas y el \\\"Campeón\\\" que es el funcionario con más puntos dentro del área.\"},{\"title\":\"3. Posición institucional\",\"text\":\"Muestra su posición entre todos los funcionarios de la CGR. Ejemplo: Posición 10 de 705\"}]}',4,0,0,'2026-04-08 20:03:48','2026-04-08 20:08:09'),
(76,23,'Visite el Ranking para ver su posición','link','{\"url\":\"https://cgrsegura.cgr.go.cr/leaderboard\"}',8,1,3,'2026-04-08 20:09:25','2026-04-12 22:44:17'),
(77,23,'Nota:','note','{\"text\":\"Las posiciones en el ranking se actualizan cada 30 minutos, entonces si todavia no se actualizan sus puntos, no se preocupe!!! Intente más tarde\"}',9,0,0,'2026-04-08 20:10:47','2026-04-09 07:43:33'),
(78,24,'Mi Perfil','text','{\"text\":\"En \\\"Mi Perfil\\\" va a encontrar sus datos y el nivel actual. Conforme se sumen puntos se puede subir de nivel y obtener distintas recompensas.\\n\\nAdemás se puede visualizar la posición en el ranking y la cantidad de insignias ganadas.\"}',1,0,0,'2026-04-08 20:16:22','2026-04-08 20:27:05'),
(79,24,'Perfil1','image','{\"file_url\":\"/uploads/course_content/285de713-8efb-4fd8-8f12-3c725f800776.png\",\"original_name\":\"Screenshot_49.png\",\"mime_type\":\"image/png\",\"size\":420090}',2,0,0,'2026-04-08 20:16:35','2026-04-08 20:16:35'),
(80,24,'Niveles','bullets','{\"items\":[{\"title\":\"Nivel 1 Novato\",\"text\":\"El primer paso: aseguras tu espacio y comprendes que la reglas para inciar el camino de la seguridad.\"},{\"title\":\"Nivel 2 Iniciado\",\"text\":\"Ya conoces las reglas del juego y sabes identificar las señales de alerta básicas.\"},{\"title\":\"Nivel 3 Defensor\",\"text\":\" Eres la primera línea de protección; tus contraseñas y hábitos son tu mejor escudo.\"},{\"title\":\"Nivel 4 Protector\",\"text\":\"Proteges no solo tu información, sino la integridad de los datos de todo tu equipo.\"},{\"title\":\"Nivel 5 Guardián\",\"text\":\"Mantienes un entorno seguro y detectas amenazas antes de que se vuelvan un problema.\"},{\"title\":\"Nivel 6 Vigilante\",\"text\":\"Tu ojo crítico es clave; supervisas procesos y actúas con agilidad ante riesgos potenciales.\"},{\"title\":\"Nivel 7 Centinela\",\"text\":\"Eres un referente de confianza; la seguridad es parte natural de cada una de tus tareas.\"},{\"title\":\"Nivel 8 Maestro Segur@\",\"text\":\"¡Meta alcanzada! Dominas todos los fundamentos esenciales para un entorno laboral seguro.\"},{\"title\":\"Nivel 9 CISO Honorario\",\"text\":\"Rango de Élite: Tu compromiso extra te convierte en un estratega y asesor para los demás.\"},{\"title\":\"Nivel 10 Leyenda Cyber\",\"text\":\"Máxima Distinción: Has superado todos los retos. Tu conocimiento es la máxima defensa de la organización.\"}]}',4,0,0,'2026-04-08 20:21:17','2026-04-15 17:53:50'),
(81,24,'Los niveles de la plataforma son los siguientes:','text','{\"text\":\"Los niveles de la plataforma son los siguientes:\"}',3,0,0,'2026-04-08 20:25:38','2026-04-08 20:25:40'),
(82,24,'Nivel Máximo','note','{\"text\":\"La meta base para todo el personal es el Nivel 8, el cual se obtiene al completar los módulos obligatorios. Quienes deseen destacar podrán alcanzar los niveles 9 y 10 mediante la participación en retos y actividades opcionales\"}',5,0,0,'2026-04-08 20:26:40','2026-04-13 19:15:39'),
(83,24,'Entre a \"Mi Perfil\" y revise su perfil','link','{\"url\":\"https://cgrsegura.cgr.go.cr/profile\"}',6,1,2,'2026-04-08 20:28:12','2026-04-12 22:44:28'),
(84,25,'Cuestionario','text','{\"text\":\"Al final de cada módulo, debe aprobar un quiz. Si obtiene la nota mínima, el sistema generará automaticamente un certificado digital a su nombre\"}',1,0,0,'2026-04-08 20:29:39','2026-04-09 16:46:17'),
(85,26,'Descúbralas','note','{\"text\":\"Durante la ejecución de los módulos va a ir ganando insignias, pero algunas estan escondidas.... será que las puede encontrar?\"}',4,0,0,'2026-04-08 21:24:09','2026-04-09 07:41:42'),
(87,19,'Confirmación del programa de capacitación','confirmation','{\"description\":\"¿Confirma que ha comprendido la metodología y el cronograma de capacitación para este año?\",\"option1\":\"Si confirmo\",\"option2\":\"No\",\"correctOption\":1}',11,1,0,'2026-04-09 14:35:27','2026-04-09 14:47:44'),
(88,25,'Certificado','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/09f727ff-7bf3-4f8e-9fad-16190356a80d.png\",\"original_name\":\"Screenshot_52.png\",\"mime_type\":\"image/png\",\"size\":62497}',2,0,1,'2026-04-09 16:54:25','2026-04-12 22:44:41'),
(89,25,'Certificados','text','{\"text\":\"Todos los certificados se guardan en el perfil. Puede descargarlos en formato PDF\"}',3,0,0,'2026-04-09 16:55:22','2026-04-09 16:55:22'),
(90,25,'Certificados','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/a599ec3c-26bf-490a-95d9-6593f0144e73.png\",\"original_name\":\"Screenshot_53.png\",\"mime_type\":\"image/png\",\"size\":75183}',4,0,0,'2026-04-09 16:56:48','2026-04-09 16:56:48'),
(92,21,'Nota','note','{\"text\":\"¿Sabías que...? Según estudios, la gamificación aumenta la retención de conocimientos en un 40% comparado con los cursos tradicionales. ¡Estás aprendiendo de la forma más eficiente!\"}',3,0,0,'2026-04-09 17:39:03','2026-04-09 17:39:03'),
(93,15,'Directrices y lineamientos de Seguridad de la Información','heading','{\"text\":\"Directrices y lineamientos de Seguridad de la Información\"}',1,0,0,'2026-04-09 20:34:35','2026-04-09 20:34:35'),
(94,15,'Cuaderno de NotebookLM Con la normativa','link','{\"url\":\"https://notebooklm.google.com/notebook/17f51fc1-1bef-40f2-b278-2a9f88dc5108\"}',11,1,0,'2026-04-09 20:51:25','2026-04-12 20:29:20'),
(95,15,'Intro','text','{\"text\":\"La Contraloría General de la República dispone de un Sistema de Gestión de Seguridad de la Información (SGSI) actualizado con el estándar internacional ISO/IEC 27001:2022, el cual es el estándar internacional más reconocido a nivel mundial para la gestión de la Seguridad de la Información. Este marco lo componen: \"}',2,0,0,'2026-04-09 20:51:34','2026-04-12 20:25:29'),
(97,15,'Marco Normativo','bullets','{\"items\":[{\"title\":\"Directrices de Seguridad de la Información\",\"text\":\"emitidas por el Despacho Contralor mediante la resolución R-DC-00069-2025. Estas directrices actualizan y adaptan el marco interno a la norma internacional ISO/IEC 27001 en su versión 2022. Su meta es garantizar la confidencialidad, integridad y disponibilidad de toda la información institucional, independientemente de si es impresa, almacenada o transmitida digitalmente\"},{\"title\":\"Lineamientos de seguridad de la Información\",\"text\":\"Emitidos por la Gerencia de la División de Gestión de Apoyo (DGA-0056-2025) para operativizar las directrices.\"},{\"title\":\"Otras Resoluciones y guias\",\"text\":\"Directrices de Información de acceso restringido, Directrices de Uso Ético y Responsable del IA, entre otros.\"}]}',3,0,0,'2026-04-12 20:03:53','2026-04-12 20:26:27'),
(98,15,'Directrices de Seguridad de la Información','link','{\"url\":\"https://drive.google.com/file/d/1RKt03SuJLoojN6d4wtn0G8oNqlp6LDt4/view\"}',5,1,1,'2026-04-12 20:08:37','2026-04-12 20:10:49'),
(99,15,'Lineamientos de Seguridad de la Información','link','{\"url\":\"https://drive.google.com/file/d/17G9199zqxZjVNm3vynrN2uOmFuJ2aYbu/view\"}',6,1,1,'2026-04-12 20:09:07','2026-04-12 20:10:48'),
(100,15,'Acatamiento','text','{\"text\":\"Estos documentos son de acatamiento obligatorio por todo el personal. Favor de acceder a los documentos. Estos pueden ser ubicados también en la sección de Documentos / Seguridad de la Información\"}',4,0,0,'2026-04-12 20:10:37','2026-04-12 20:10:49'),
(101,15,'Entendimiento','text','{\"text\":\"Para facilitar su entendimiento y consulta se habilitó un cuaderno de NotebookLM, en el cual se encuentra toda la normativa relacionada con la seguridad de la información. En este cuaderno puede realizar consultas relacionadas con la normativa con ayuda de la Inteligencia Artificial.\"}',9,0,0,'2026-04-12 20:12:08','2026-04-27 20:48:15'),
(102,15,'Imagen','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/d33a8acb-8060-4a2e-8dbe-44702c3fc26c.png\",\"original_name\":\"Screenshot_54.png\",\"mime_type\":\"image/png\",\"size\":349677}',10,0,0,'2026-04-12 20:14:57','2026-04-12 20:29:21'),
(106,15,'Ahora que ya tiene acceso al cuaderno, ingrese y realice la siguiente pregunta: ¿En cuál lineamiento de seguridad de la información se habla sobre la información confidencial?','interactive_input','{\"description\":\"¿Cuál es el número del lineamiento? Pista: La respuesta sigue el formato X.X.X\",\"validation_type\":\"exact\",\"correct_answer\":\"E.3.2\",\"regex_pattern\":\"\",\"placeholder\":\"Escribe tu respuesta aquí...\"}',13,1,2,'2026-04-12 20:22:20','2026-04-29 15:15:02'),
(107,15,'Elementos de Lineamientos','bullets','{\"items\":[{\"title\":\"Controles Organizacionales\",\"text\":\"Definen la gobernanza, las políticas y cómo se gestiona la seguridad desde la administración\"},{\"title\":\"Controles de Personas\",\"text\":\"Se enfocan en la formación, responsabilidades y el comportamiento seguro del personal\"},{\"title\":\"Controles Físicos\",\"text\":\"Protegen las instalaciones, el acceso a oficinas y los equipos tangibles\"},{\"title\":\"Controles Tecnológicos\",\"text\":\"Abarcan el software, cifrado, redes y todas las defensas digitales contra ciberataques\"}]}',8,0,0,'2026-04-12 20:28:16','2026-04-12 20:29:32'),
(108,15,'Asegurar','text','{\"text\":\"Para asegurar una protección integral en seguridad de la información, la CGR organiza sus reglas en cuatro pilares críticos:\"}',7,0,0,'2026-04-12 20:29:15','2026-04-12 20:29:31'),
(109,17,'Lineamientos de Seguridad de la Información H.1 Acceso Lógico','note','{\"text\":\"H.1.1 Todo el personal tendrá asignada una identidad digital intransferible, compuesta por un nombre de usuario y una contraseña, o bien un certificado digital reconocido por la CGR. Bajo ninguna circunstancia se debe entregar a terceras personas esas credenciales\"}',2,0,0,'2026-04-13 00:34:59','2026-04-13 00:53:41'),
(110,17,'Reflexión','note','{\"text\":\"Las contraseñas son como la ropa interior. No puedes dejar que nadie las vea, debes cambiarlas regularmente y no debes compartirlas con extraños\"}',5,0,0,'2026-04-13 00:42:52','2026-04-13 02:00:13'),
(113,17,'Recomendaciones','heading','{\"text\":\"Recomendaciones para las contraseñas\"}',6,0,0,'2026-04-13 00:52:53','2026-04-13 02:00:11'),
(116,17,'Aquí puede probar sus contraseñas','password_tester','{\"text\":\"\"}',10,0,5,'2026-04-13 01:04:34','2026-04-13 03:07:00'),
(117,17,'Su contraseña es fuerte?','heading','{\"text\":\"Su contraseña es fuerte?\"}',8,0,0,'2026-04-13 01:05:49','2026-04-13 03:07:00'),
(118,17,'Ejerccio','text','{\"text\":\"En el siguiente ejercicio puede probar que tan fuertes son sus contraseñas. No se preocupe, sus contraseñas no quedan guardadas en el sistema, se procesan de forma local en su computadora.\"}',9,0,0,'2026-04-13 01:07:58','2026-04-13 03:07:00'),
(119,17,'¿Cómo le fue con la cuenta CGR?','multiple_choice','{\"description\":\"¿Cuál fue el tiempo estimado para hackear la contraseña de la computadora del trabajo?\",\"options\":[{\"text\":\"Instante\",\"is_correct\":false},{\"text\":\"Minutos\",\"is_correct\":false},{\"text\":\"Horas\",\"is_correct\":false},{\"text\":\"Dias\",\"is_correct\":false},{\"text\":\"Meses\",\"is_correct\":false},{\"text\":\"Años\",\"is_correct\":false},{\"text\":\"Siglos\",\"is_correct\":false}]}',13,1,5,'2026-04-13 01:12:00','2026-04-15 15:31:02'),
(120,17,'Pass','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/2244ff08-e06a-474d-9497-94e19ccf18c9.svg\",\"original_name\":\"pass.svg\",\"mime_type\":\"image/svg+xml\",\"size\":20302}',7,0,0,'2026-04-13 01:47:34','2026-04-13 02:00:09'),
(121,17,'Recomendaciones','bullets','{\"items\":[{\"title\":\"Uso Exclusivo\",\"text\":\"Bajo ninguna circunstancia, ni siquiera por razones de urgencia o cuando si un técnico se la solicita, se deben compartir las credenciales de acceso. La confianza institucional se basa en la confidencialidad y los permisos de cada usuario\"},{\"title\":\"Confidencialidad Absoluta\",\"text\":\"Debe evitar anotar contraseñas en lugares inseguros, como notas en el celular, archivos de texto, documentos y hojas de cálculo. Menos en papelitos!!!\"},{\"title\":\"Firma Digital\",\"text\":\"En caso de utilizar firma digital, debe custodiar de forma segura la tarjeta física, y asegurar que siempre  permanezca bajo su control exclusivo.\"}]}',4,0,0,'2026-04-13 01:58:23','2026-04-13 02:02:35'),
(122,17,'¿Cómo le fue con las contraseñas personales?','multiple_choice','{\"description\":\"¿Cuál fue el menor tiempo estimado para hackear alguna contraseña de una cuenta personal?\",\"options\":[{\"text\":\"Instante\",\"is_correct\":false},{\"text\":\"Minutos\",\"is_correct\":false},{\"text\":\"Horas\",\"is_correct\":false},{\"text\":\"Dias\",\"is_correct\":false},{\"text\":\"Meses\",\"is_correct\":false},{\"text\":\"Años\",\"is_correct\":false},{\"text\":\"Siglos\",\"is_correct\":false}]}',14,1,5,'2026-04-13 02:07:54','2026-04-15 15:31:20'),
(123,17,'Contraseñas Filtradas','heading','{\"text\":\"Contraseñas Filtradas\"}',15,0,0,'2026-04-13 02:10:29','2026-04-13 03:21:18'),
(124,17,'Problemas','text','{\"text\":\"¿Cúal es el problema con utilizar la misma contraseña en distintos sitios? Analice el siguiente caso:\\n\\nAna usa la contraseña \\\"Abril1989\\\" en la cuenta de correo electrónico de la CGR (ana.targaryen@cgr.go.cr). Como le cuesta acordarse de distintas contraseñas usa la misma contraseña y correo para su cuenta de Canva.\\n\\nCanva sufrió un ciberataque y le robaron toda la información de los usuarios, incluido el correo y las contraseñas.\\n\\nEl atacante usa esas credenciales para intentar acceder a otros sitios, como Gmail, Netflix u otros. Ahora el atacante tiene acceso a las cuentas de Ana, y puede hacerse pasar por ella para enviar correos Phishing o robar información confidencial.\"}',16,0,0,'2026-04-13 02:18:00','2026-04-13 03:21:18'),
(125,17,'Have I been Pwned','link','{\"url\":\"https://haveibeenpwned.com/\"}',18,1,0,'2026-04-13 02:28:39','2026-04-13 03:21:18'),
(128,17,'Su contraseña se encuentra en más de una filtración de datos?','multiple_choice','{\"description\":\"Digite su contraseña en el componente anterior y dé click en el botón \\\"Verificar Filtraciones\\\" y conteste:\",\"options\":[{\"text\":\"Si, oh oh, tengo que cambiarla\",\"is_correct\":false},{\"text\":\"No, estoy salvado!\",\"is_correct\":false}]}',12,1,5,'2026-04-13 02:56:33','2026-04-16 21:46:34'),
(129,17,'¿Cómo puede darse cuenta si su cuenta ha sido vulnerada?','note','{\"text\":\"Puede ingresar al sitio Have I Been Pwned y veriticar sus correos electrónicos\"}',17,0,0,'2026-04-13 03:06:48','2026-04-15 15:31:30'),
(130,17,'Cantidad de Breaches','interactive_input','{\"description\":\"¿Cúal fue la cantidad de data breaches que aparecieron con su correo de la CGR? (Debe digitar solo el número ej. 24 )\",\"validation_type\":\"regex\",\"correct_answer\":\"\",\"regex_pattern\":\"^[0-9]+$\",\"placeholder\":\"Escribe tu respuesta aquí...\"}',19,1,5,'2026-04-13 03:09:24','2026-04-13 03:24:20'),
(131,17,'Filtraciones','bullets','{\"items\":[{\"title\":\"Base de datos de filtraciones\",\"text\":\"El sistema está conectado a una gran base de datos de filtraciones de contraseñas. Si le da click al botón de \\\"Verificar filtraciones\\\", se busca su contraseña y se determina la cantidad de veces que ha sido filtrada\"},{\"title\":\"¿Qué significa que la contraseña ha sido filtrada?\",\"text\":\"Qué se la robaron!, y anda dando vueltas por los lugares más oscuros de internet\"},{\"title\":\"¿Qué debería hacer con esa contraseña?\",\"text\":\"Desecharla, cambiarla inmediatamente y no volverla a utilizar nunca!!!\"},{\"title\":\"¿Y si es compleja y el tiempo de hackeo es de siglos estoy seguro?\",\"text\":\"Si es compleja, y el tiempo de hackeo es alto pero aparece en la base de datos de filtraciones, ya no puede reutilizar esa contraseña nunca más. \"}]}',12,0,0,'2026-04-13 03:18:58','2026-04-27 21:27:33'),
(132,18,'Gestor de Contraseñas','heading','{\"text\":\"Gestor de Contraseñas\"}',3,0,0,'2026-04-13 03:35:04','2026-04-13 03:35:18'),
(133,18,'Ventajas','bullets','{\"items\":[{\"title\":\"Generación de Claves Robustas\",\"text\":\"El error más común es usar contraseñas fáciles de adivinar (como \\\"CGR2026*\\\"). El gestor crea claves aleatorias y complejas (ej. $uP9!z-o-Rr4aqL2) que son prácticamente imposibles de descifrar mediante ataques de fuerza bruta.\"},{\"title\":\"Almacenamiento Seguro (Cifrado)\",\"text\":\"A diferencia de anotarlas en un post-it o en una hoja de calculo, el gestor utiliza algoritmos de cifrado de grado militar. Esto garantiza que, aunque alguien tuviera acceso a su dispositivo, no podría leer sus contraseñas sin la contraseña maestra\"},{\"title\":\"Autocompletado y Productividad\",\"text\":\"El gestor detecta cuándo está en un sitio web o aplicación institucional y rellena automáticamente con sus datos. Esto no solo ahorra tiempo, sino que también protege del phishing, ya que el gestor no ingresa las claves en un sitio falso que intente suplantar a la CGR.\"},{\"title\":\"Sincronización y Respaldo\",\"text\":\"Permite tener los accesos disponibles en distintos dispositivos (computadora, teléfono, tablet) de forma segura y actualizada en tiempo real.\"}]}',6,0,0,'2026-04-13 03:40:34','2026-04-13 03:43:05'),
(134,18,'Lineamientos de Segurida de la Información ','note','{\"text\":\"H.1.8 Todo el personal deberá utilizar un administrador de contraseñas seguro aprobado por la UTI y el CISO para almacenar sus contraseñas. Se prohíbe el almacenamiento de contraseñas en navegadores web u otros medios no seguros\"}',4,0,0,'2026-04-13 03:42:58','2026-04-13 03:43:05'),
(135,18,'Bitwarden: El Administrador de contraseñas','heading','{\"text\":\"Bitwarden: El Administrador de contraseñas\"}',7,0,0,'2026-04-13 03:43:43','2026-04-13 19:41:34'),
(136,18,'Bitwarden','text','{\"text\":\"El administrador de contraseñas recomendado se llama Bitwarden y es una herramienta de código abierto y, al ser de código abierto, el código de programación de Bitwarden es público y puede ser auditado por expertos en seguridad de todo el mundo. Esto garantiza que no existan \\\"puertas traseras\\\" y que cualquier vulnerabilidad se detecte y corrija mucho más rápido que en un software privado.\\n\\nProceda a instalarlo y configurarlo en su equipo\"}',9,0,0,'2026-04-13 03:45:36','2026-04-13 04:31:51'),
(137,18,'Bitwarden','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/09b1b4d9-9f3f-4caa-870a-24085d5fc50d.png\",\"original_name\":\"Screenshot_56.png\",\"mime_type\":\"image/png\",\"size\":295420}',8,0,0,'2026-04-13 03:46:45','2026-04-13 03:46:48'),
(138,18,'Guia operativa  SGSI-H1-G14 Administrador de Contraseñas Bitwarden','link','{\"url\":\"https://docs.google.com/document/d/1u2yeuT2Ji5N_DS4HiICyJAlFTMq9UkjFS4K6TrN_dZQ/edit?tab=t.0#heading=h.nnxbanft1qjh\"}',10,1,5,'2026-04-13 04:31:20','2026-04-13 16:37:53'),
(139,18,'Tengo instalado y configurado Bitwarden','confirmation','{\"description\":\"Tengo instalado y configurado Bitwarden\",\"option1\":\"Si\",\"option2\":\"No\",\"correctOption\":1}',14,1,5,'2026-04-13 04:32:23','2026-04-27 17:24:56'),
(140,27,'Ejercicios Opcionales','heading','{\"text\":\"Ejercicios Opcionales\"}',1,0,0,'2026-04-13 04:34:01','2026-04-13 04:34:29'),
(141,27,'1. Verificar contraseña en Bitwarden','interactive_input','{\"description\":\"Utilice el verificador de contraseñas de Bitwarden y verifique la contraseña \\\"contraloria\\\" cuantas veces ha sido comprometida (No es su clave de CGR!, es el texto \\\"contraloria\\\") Pista: Revise la guia de Bitwarden en el punto C.1 Crear una entrada de credenciales para saber como resolverlo.\",\"validation_type\":\"exact\",\"correct_answer\":\"4096\",\"regex_pattern\":\"\",\"placeholder\":\"Escribe tu respuesta aquí...\"}',3,0,5,'2026-04-13 04:38:17','2026-05-04 18:08:32'),
(142,27,'2. Crear un envio de Texto de Bitwarden y agregarlo al campo','interactive_input','{\"description\":\"Crear un envio de Texto de Bitwarden y agregarlo al campo. Puede revisar la guia en el punto C.3 Envío de datos seguro\",\"validation_type\":\"regex\",\"correct_answer\":\"\",\"regex_pattern\":\"^https:\\\\/\\\\/send\\\\.bitwarden\\\\.com\\\\/#[a-zA-Z0-9_-]+\\\\/[a-zA-Z0-9_-]+$\",\"placeholder\":\"Escribe tu respuesta aquí...\"}',4,0,5,'2026-04-13 04:40:42','2026-05-04 18:08:39'),
(143,27,'3. Captura la Bandera: Una bandera (o flag) en ciberseguridad es una cadena de texto o archivo oculto secreto que los participantes deben encontrar para resolver retos.','interactive_input','{\"description\":\"Abrir una nueva pestaña de Chrome y acceder al link de Bitwarden Send y recolectar la bandera.\\nhttps://send.bitwarden.com/#fwHvyXkvH0qMfbQrAE3vpg/YEGhJQrzHnVlokCZPHrhqg\",\"validation_type\":\"exact\",\"correct_answer\":\"CGR{B1tw4rd3n_53nd}\",\"regex_pattern\":\"\",\"placeholder\":\"Escribe tu respuesta a111quí...\"}',5,0,5,'2026-04-13 04:44:40','2026-05-04 18:08:49'),
(144,28,'Reto Final!','quiz','{\"description\":\"Está preparado?\",\"quiz_id\":2}',1,1,30,'2026-04-13 07:33:23','2026-04-13 16:39:09'),
(145,27,'Opcionales','text','{\"text\":\"Estos ejercicios son completamente opcionales y si quiere lo puede saltar. \\n\\nEsta es una buena oportunidad para ganar puntos extra y subir en el Ranking\"}',2,0,0,'2026-04-13 07:42:51','2026-04-13 07:43:05'),
(147,29,'Retroalimentación','survey','{\"description\":\"¡Felicidades por completar el primer módulo! Su opinión nos ayuda a mejorar los futuros contenidos del Curso CGR Cybersegur@\",\"survey_id\":2}',1,1,10,'2026-04-13 07:50:29','2026-05-04 19:31:47'),
(148,25,'Reportes','heading','{\"text\":\"Reportes\"}',5,0,0,'2026-04-13 17:04:02','2026-04-13 17:04:02'),
(149,25,'Reportes','text','{\"text\":\"Si encuentra un error en la plataforma o tiene dudas o consultas puede escribir al Oficial de Seguridad de la Información (CISO) mario.andres.zamora@cgr.go.cr por medio de Chat o correo.\"}',6,0,0,'2026-04-13 17:05:09','2026-04-13 17:05:09'),
(150,18,'MFA','heading','{\"text\":\"Autenticación Multifactor\"}',15,0,0,'2026-04-13 19:22:23','2026-04-27 17:24:55'),
(151,18,'MFA','text','{\"text\":\"El MFA son las siglas de Multi-Factor Authentication (en español, Autenticación de Múltiples Factores) y en términos sencillos, es una medida de seguridad que requiere que dos o más pruebas de identidad antes de dejar ingresar a una cuenta o sistema. \\n\\nEn lugar de confiar solo en una contraseña, el MFA añade \\\"capas\\\" extra de protección. Ya que como vimos en la lección pasada, las contraseñas se pueden filtrar y exponer los datos a los atacantes.\\n\\nSi nos roban el password pero nuestra cuenta tiene configurado el MFA, nos aseguramos que no ingresen a las cuentas, y nos podemos dar cuenta si alguien esta intentando entrar y cambiar la contraseña\"}',17,0,0,'2026-04-13 19:24:32','2026-04-27 17:24:53'),
(152,18,'31. Guía para activar la Verificación en 2 pasos.','link','{\"url\":\"https://docs.google.com/document/d/1oAENmBDFL-WGgoDc99KPhIpEF3eEAiC87AhUQVjxVHw/edit?tab=t.0\"}',18,1,0,'2026-04-13 19:28:40','2026-04-27 17:24:52'),
(153,18,'Recomendación','note','{\"text\":\"Active MFA en todas sus cuentas personales de correo electrónico, Whatsapp, Netflix. Y para sus cuentas de banco utilice SIEMPRE Firma digital. \"}',19,0,0,'2026-04-13 19:30:11','2026-04-27 17:24:51'),
(154,18,'2fa','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/e38a2438-e51c-4497-9d70-9d6c8b3f19ce.jpg\",\"original_name\":\"2fa.jpg\",\"mime_type\":\"image/jpeg\",\"size\":105573}',20,0,0,'2026-04-13 19:31:31','2026-04-27 17:24:49'),
(155,18,'Existen varios tipos de MFA','text','{\"text\":\"Existen varios tipos de MFA:\"}',21,0,0,'2026-04-13 19:31:56','2026-04-27 17:24:49'),
(156,18,'Tipos','bullets','{\"items\":[{\"title\":\"Token Celular\",\"text\":\"Usa la tecnologia TOTP (Time-based One-Time Password) para generar uno o más códigos de un solo uso.\"},{\"title\":\"Aplicación Autenticadora\",\"text\":\"Son aplicaciones como Google Authenticator que permiten generar codigos o notificaciones que el usuario puede hacer clic para aceptar el inicio de sesión\"},{\"title\":\"Correo Electrónico\",\"text\":\"Una de las más usadas, y permite enviar un código a su correo electrónico registrado en la aplicación para verificar su identidad\"}]}',22,0,0,'2026-04-13 19:34:46','2026-04-27 17:24:48'),
(157,18,'En las cuentas de CGR es obligatorio el uso de MFA, pero en sus cuentas personales?','multiple_choice','{\"description\":\"Tiene activado el MFA en:\",\"options\":[{\"text\":\"1. Solo en el correo electrónico personal\",\"is_correct\":false},{\"text\":\"2. Solo en el Whatsapp\",\"is_correct\":false},{\"text\":\"3. Solo en cuentas de entretenimiento (Netflix)\",\"is_correct\":false},{\"text\":\"4. En Ninguna\",\"is_correct\":false},{\"text\":\"5. En todas las anteriores\",\"is_correct\":false},{\"text\":\"6. Solo 1 y 2\",\"is_correct\":false}]}',23,1,0,'2026-04-13 19:38:18','2026-04-27 17:24:47'),
(158,18,'Lineamientos de Seguridad de la Información','note','{\"text\":\"H.1.3 La autenticación con dos factores (2FA) deberá utilizarse de manera obligatoria en todas las soluciones tecnológicas que lo permitan. La UTI implementará la autenticación con dos factores para los sistemas institucionales, medida que aplicará de manera igualmente obligatoria.\"}',16,0,0,'2026-04-13 19:41:24','2026-04-27 17:24:53'),
(159,17,'¿Qué hacer si su cuenta aparece en una filtración?','text','{\"text\":\"¿Qué hacer si su cuenta aparece en una filtración?\"}',20,0,0,'2026-04-16 07:03:32','2026-04-16 07:03:32'),
(160,17,'Riesgos','bullets','{\"items\":[{\"title\":\"Cambiar la contraseña\",\"text\":\"Si usaba esa misma contraseña en otros sitios (banco, redes sociales, Amazon), cámbiela en todos ellos. Los hackers usan un ataque llamado Credential Stuffing para probar su clave filtrada en otros servicios\"},{\"title\":\"Implementar MFA\",\"text\":\"Esta es su mejor defensa. Incluso si alguien tiene su contraseña, no podrá entrar sin el código de su celular.\"},{\"title\":\"Empezar a usar un Gestor de Contraseñas\",\"text\":\"Use un gestor y olvidese de las contraseñas\"}]}',21,0,0,'2026-04-16 07:05:48','2026-04-16 07:05:48'),
(172,18,'Cómo Importar contraseñas de Google Chrome?','video','{\"url\":\"https://www.youtube.com/watch?v=hKpWjidJgPo\"}',11,0,0,'2026-04-27 17:12:14','2026-04-27 17:12:36'),
(173,18,'Imagen','image','{\"description\":\"\",\"file_url\":\"/uploads/course_content/d088dc75-bca5-408f-8dcc-9de405d23d87.png\",\"original_name\":\"11111.png\",\"mime_type\":\"image/png\",\"size\":55419}',13,0,0,'2026-04-27 17:23:37','2026-04-27 17:24:57'),
(174,18,'Nota','note','{\"text\":\"Si no puede ver el icono de Bitwarden haga click donde se muestra en la imagen\"}',12,0,0,'2026-04-27 17:24:43','2026-04-27 17:24:57'),
(175,27,'Evangelizador Bitwarden','assignment','{\"description\":\"1. Identificar 3 compañeros que necesiten ayuda con Bitwarden\\n2. Guiarlos en la configuración paso a paso y explicar su funcionamiento\\n3. Documentar la experiencia\\n4. Subir un documento PDF con evidencia del proceso.\"}',6,0,20,'2026-05-04 16:41:41','2026-05-04 16:41:57');
