INSERT INTO `quiz_questions` VALUES
(2,2,'Eres el atacante!!!. Para superar este desafio deberás usar tu ingenio para adivinar la contraseña que usa tu vecino, utilizando solo información que tiene publicada en redes sociales. Información como fechas, nombres, u otros pueden ser importantes. Debes digitar la clave que creas que sea en el campo de texto. Hay 3 pistas y si las utilizas se restan 10 puntos por cada una.','hack_neighbor',NULL,100,0,'','2026-04-13 07:35:07','{\"hint_penalty\":10}'),
(3,2,'Para superar este desafío, deberás ingresar un código numérico de 6 dígitos que se muestra en pantalla en el campo de texto, antes de que se acabe el tiempo. Presta mucha atención a la interfaz: mientras la línea de tiempo roja a la izquierda marca tu límite de \"hackeo\" para completar la tarea, la barra azul indica la rotación del código, el cual cambiará periódicamente como en una aplicación de autenticación real. Sé preciso y ágil, ya que cada intento fallido o código expirado aplicará una penalización que restará puntos a la recompensa final de tu lección\n\n','mfa_defender',NULL,100,0,'','2026-04-13 07:35:07','{\"rotate_time\":8,\"hack_time\":20,\"fail_penalty\":5}'),
(4,3,'Cual es el eje tematico 1','multiple_choice',NULL,1,0,'','2026-04-22 19:40:23','{}');
INSERT INTO `quizzes` VALUES
(2,1,28,'Reto Final!','quiz','Preparese para jugar!. Va a tener 2 retos. Esta no es una prueba cualquiera. Tiene 3 intentos máximos.',70,30,3,0,1,'2026-04-13 07:34:02','2026-04-29 15:20:04'),
(3,2,8,'Quiz 1','quiz','',70,30,3,0,1,'2026-04-22 19:40:23','2026-04-22 19:40:23');
