INSERT INTO `system_announcements` VALUES
(1,'Aviso: Nueva funcionalidad','Dicen que ningún gran héroe vence al jefe final en el primer intento sin aprender sus trucos. ¡Por eso habilitamos el Modo Reintento! Vuelve a entrar al examen final, pule tus habilidades y demuestra que el conocimiento es un músculo que se entrena.',1,1,'2026-04-29 19:02:49','2026-04-29 19:17:24'),
(2,'Nueva actividad opcional: Evangelizador Bitwarden ','¿Te animas a ayudar a 3 compañeros a configurar su Bitwarden? Es el momento de compartir lo que sabes, fortalecer nuestra seguridad y documentar el proceso. Revisa la seccion de ejercicios opcionales para subir la evidencia.',1,9,'2026-05-04 16:44:18','2026-05-05 15:35:01');
